     1→package export
     2→
     3→import (
     4→	"context"
     5→	"fmt"
     6→	"strings"
     7→	"sync"
     8→
     9→	"github.com/port-experimental/port-cli/internal/api"
    10→	"golang.org/x/sync/errgroup"
    11→)
    12→
    13→// Options represents export options.
    14→type Options struct {
    15→	OutputPath             string
    16→	Blueprints             []string
    17→	Format                 string
    18→	SkipEntities           bool
    19→	IncludeResources       []string
    20→	ExcludeBlueprints      []string // deep: exclude blueprint schema + all its resources
    21→	ExcludeBlueprintSchema []string // shallow: exclude only the blueprint schema, keep resources
    22→}
    23→
    24→// Validate validates export options.
    25→func (o *Options) Validate() error {
    26→	if o.OutputPath == "" {
    27→		return fmt.Errorf("output_path is required")
    28→	}
    29→
    30→	if o.Format != "" && o.Format != "json" && o.Format != "tar" {
    31→		return fmt.Errorf("format must be 'json' or 'tar'")
    32→	}
    33→
    34→	return nil
    35→}
    36→
    37→// Data represents collected export data.
    38→type Data struct {
    39→	Blueprints []api.Blueprint
    40→	Entities   []api.Entity
    41→	Scorecards []api.Scorecard
    42→	Actions    []api.Action
    43→	// BlueprintPermissions maps blueprint identifier -> permissions object.
    44→	BlueprintPermissions map[string]api.Permissions
    45→	// ActionPermissions maps action identifier -> permissions object.
    46→	ActionPermissions map[string]api.Permissions
    47→	Teams             []api.Team
    48→	Users             []api.User
    49→	Folders           []api.Folder
    50→	Pages             []api.Page
    51→	Integrations      []api.Integration
    52→	TimeoutErrors     []string // Blueprints that timed out during export
    53→}
    54→
    55→// Collector collects data from Port API concurrently.
    56→type Collector struct {
    57→	client *api.Client
    58→}
    59→
    60→// NewCollector creates a new collector.
    61→func NewCollector(client *api.Client) *Collector {
    62→	return &Collector{
    63→		client: client,
    64→	}
    65→}
    66→
    67→// shouldCollect checks if a resource type should be collected.
    68→func shouldCollect(resourceType string, includeResources []string) bool {
    69→	if len(includeResources) == 0 {
    70→		return true
    71→	}
    72→
    73→	for _, r := range includeResources {
    74→		if r == resourceType {
    75→			return true
    76→		}
    77→	}
    78→	return false
    79→}
    80→
    81→// isTimeoutError checks if an error is a timeout error (504 Gateway Timeout).
    82→func isTimeoutError(err error) bool {
    83→	if err == nil {
    84→		return false
    85→	}
    86→	errStr := strings.ToLower(err.Error())
    87→	// Check for various timeout indicators
    88→	return strings.Contains(errStr, "504") ||
    89→		strings.Contains(errStr, "gateway timeout") ||
    90→		strings.Contains(errStr, "timeout_error") ||
    91→		strings.Contains(errStr, "request was too long") ||
    92→		strings.Contains(errStr, "timeout")
    93→}
    94→
    95→// Collect collects all data from Port API concurrently.
    96→func (c *Collector) Collect(ctx context.Context, opts Options) (*Data, error) {
    97→	data := &Data{
    98→		Blueprints:           []api.Blueprint{},
    99→		Entities:             []api.Entity{},
   100→		Scorecards:           []api.Scorecard{},
   101→		Actions:              []api.Action{},
   102→		Teams:                []api.Team{},
   103→		Users:                []api.User{},
   104→		Folders:              []api.Folder{},
   105→		Pages:                []api.Page{},
   106→		Integrations:         []api.Integration{},
   107→		TimeoutErrors:        []string{},
   108→		BlueprintPermissions: make(map[string]api.Permissions),
   109→		ActionPermissions:    make(map[string]api.Permissions),
   110→	}
   111→
   112→	// Collect blueprints first (needed for other resources)
   113→	var blueprints []api.Blueprint
   114→	if shouldCollect("blueprints", opts.IncludeResources) {
   115→		allBlueprints, err := c.client.GetBlueprints(ctx)
   116→		if err != nil {
   117→			return nil, fmt.Errorf("failed to get blueprints: %w", err)
   118→		}
   119→
   120→		// Filter blueprints if specified
   121→		if len(opts.Blueprints) > 0 {
   122→			blueprintSet := make(map[string]bool)
   123→			for _, bpID := range opts.Blueprints {
   124→				blueprintSet[bpID] = true
   125→			}
   126→
   127→			for _, bp := range allBlueprints {
   128→				if identifier, ok := bp["identifier"].(string); ok && blueprintSet[identifier] {
   129→					blueprints = append(blueprints, bp)
   130→				}
   131→			}
   132→		} else {
   133→			blueprints = allBlueprints
   134→		}
   135→
   136→		iterBlueprints, dataBlueprints := ApplyBlueprintExclusions(blueprints, opts.ExcludeBlueprints, opts.ExcludeBlueprintSchema)
   137→		data.Blueprints = dataBlueprints
   138→		blueprints = iterBlueprints
   139→	} else {
   140→		// Still need blueprints for dependent resources
