   405→func ApplyBlueprintExclusions(all []api.Blueprint, excludeDeep, excludeSchema []string) (iterList, dataList []api.Blueprint) {
   406→	if len(excludeDeep) == 0 && len(excludeSchema) == 0 {
   407→		return all, all
   408→	}
   409→	deepSet := make(map[string]bool, len(excludeDeep))
   410→	for _, id := range excludeDeep {
   411→		deepSet[id] = true
   412→	}
   413→	schemaSet := make(map[string]bool, len(excludeSchema))
   414→	for _, id := range excludeSchema {
   415→		schemaSet[id] = true
   416→	}
   417→
   418→	for _, bp := range all {
   419→		id, _ := bp["identifier"].(string)
   420→		if deepSet[id] {
   421→			// Deep exclusion: skip in both lists
   422→			continue
   423→		}
   424→		// In iteration list (fetches dependent resources) for everyone not deep-excluded
   425→		iterList = append(iterList, bp)
   426→		if schemaSet[id] {
   427→			// Schema-only exclusion: skip in data (output) list only
   428→			continue
   429→		}
   430→		dataList = append(dataList, bp)
   431→	}
   432→	return iterList, dataList
   433→}
