   229→// getCalculationPropertyTargets extracts blueprint identifiers from calculation properties.
   230→// Calculation formulas may reference other blueprints via relations.
   231→func getCalculationPropertyTargets(bp api.Blueprint) []string {
   232→	targets := []string{}
   233→	calcProps, ok := bp["calculationProperties"].(map[string]interface{})
   234→	if !ok {
   235→		return targets
   236→	}
   237→
   238→	// Build map of relation name -> target blueprint
   239→	relationTargets := make(map[string]string)
   240→	relations, ok := bp["relations"].(map[string]interface{})
   241→	if ok {
   242→		for relName, rel := range relations {
   243→			relMap, ok := rel.(map[string]interface{})
   244→			if !ok {
   245→				continue
   246→			}
   247→			if target, ok := relMap["target"].(string); ok {
   248→				relationTargets[relName] = target
   249→			}
   250→		}
   251→	}
   252→
   253→	// Regex to find relation references in calculations
   254→	// Format: relations.relationName.property or .relations.relationName
   255→	relPattern := regexp.MustCompile(`\.?relations\.(\w+)`)
   256→
   257→	for _, prop := range calcProps {
   258→		propMap, ok := prop.(map[string]interface{})
   259→		if !ok {
   260→			continue
   261→		}
   262→
   263→		calc, ok := propMap["calculation"].(string)
   264→		if !ok || calc == "" {
   265→			continue
   266→		}
   267→
   268→		// Find all relation references in the calculation
   269→		matches := relPattern.FindAllStringSubmatch(calc, -1)
   270→		for _, match := range matches {
   271→			if len(match) >= 2 {
   272→				relName := match[1]
   273→				if target, ok := relationTargets[relName]; ok {
   274→					targets = append(targets, target)
   275→				}
   276→			}
   277→		}
   278→	}
   279→
   280→	return targets
   281→}
