   307→// getOwnershipDependency extracts the blueprint identifier that this blueprint's ownership
   308→// depends on. Only inherited ownership creates a dependency, and it depends on the target
   309→// blueprint of the first relation segment in the ownership path.
   310→func getOwnershipDependency(bp api.Blueprint) string {
   311→	ownership, ok := bp["ownership"].(map[string]interface{})
   312→	if !ok {
   313→		return ""
   314→	}
   315→
   316→	ownershipType, _ := ownership["type"].(string)
   317→	if ownershipType != "Inherited" {
   318→		return ""
   319→	}
   320→
   321→	path, _ := ownership["path"].(string)
   322→	if path == "" {
   323→		return ""
   324→	}
   325→
   326→	parts := strings.Split(path, ".")
   327→	if len(parts) == 0 || parts[0] == "" {
   328→		return ""
   329→	}
   330→
   331→	relations, ok := bp["relations"].(map[string]interface{})
   332→	if !ok {
   333→		return ""
   334→	}
   335→
   336→	relationDef, ok := relations[parts[0]].(map[string]interface{})
   337→	if !ok {
   338→		return ""
   339→	}
   340→
   341→	target, _ := relationDef["target"].(string)
   342→	return target
   343→}
