   535→// FlattenLevels converts leveled blueprints to a flat slice in dependency order.
   536→func FlattenLevels(levels [][]api.Blueprint) []api.Blueprint {
   537→	var result []api.Blueprint
   538→	for _, level := range levels {
   539→		result = append(result, level...)
