package import_module

import (
	"context"
	"encoding/json"
	"fmt"
	"reflect"
	"regexp"
	"sort"
	"strings"
	"sync"

	"github.com/port-experimental/port-cli/internal/api"
	"github.com/port-experimental/port-cli/internal/config"
	"github.com/port-experimental/port-cli/internal/modules/export"
)

// Module handles importing data to Port.
type Module struct {
	client *api.Client
}

// NewModule creates a new import module.
func NewModule(orgConfig *config.OrganizationConfig) *Module {
	client := api.NewClient(orgConfig.ClientID, orgConfig.ClientSecret, orgConfig.APIURL, 0)
	return &Module{
		client: client,
	}
}

// Options represents import options.
// ProgressCallback is called to report import progress.
// phase is the current phase name, current is the number of items processed, total is the total count.
type ProgressCallback func(phase string, current, total int)

// Options represents import options.
type Options struct {
	InputPath              string
	DryRun                 bool
	SkipEntities           bool
	IncludeResources       []string
	ExcludeBlueprints      []string // deep: exclude blueprint schema + all its resources
	ExcludeBlueprintSchema []string // shallow: exclude only the blueprint schema, keep resources
	Verbose                bool
	ShowPagesPipeline      bool
	ProgressCallback       ProgressCallback
	LogCallback            func(string)
}

// ValidationWarning represents a pre-import validation warning.
type ValidationWarning struct {
	Type    string // "cycle", "missing_dependency", "protected_resource"
	Message string
	Details []string
}

// Result represents the result of an import operation.
type Result struct {
	Success             bool
	Message             string
	BlueprintsCreated   int
	BlueprintsUpdated   int
	EntitiesCreated     int
	EntitiesUpdated     int
	ScorecardsCreated   int
	ScorecardsUpdated   int
	ActionsCreated      int
	ActionsUpdated      int
	TeamsCreated        int
	TeamsUpdated        int
	UsersCreated        int
	UsersUpdated        int
	PagesCreated        int
	PagesUpdated        int
	IntegrationsUpdated int
	Errors              []string
	ErrorsByCategory    map[string][]string // Categorized errors for verbose output
	Warnings            []ValidationWarning // Pre-import validation warnings
	DiffResult          *DiffResult
	SidebarPipeline     []string
}

type SidebarPipelineOperation struct {
	ResourceType string
	Identifier   string
	Folder       api.Folder
	Page         api.Page
}

type SidebarPipelineStep struct {
	Operations []SidebarPipelineOperation
}

// Execute performs the import operation.
func (m *Module) Execute(ctx context.Context, opts Options) (*Result, error) {
	// Load data
	loader := NewLoader()
	data, err := loader.LoadData(opts.InputPath)
	if err != nil {
		return nil, fmt.Errorf("failed to load data: %w", err)
	}

	// Apply blueprint exclusions before diffing/importing
	applyDataExclusion(data, opts.ExcludeBlueprints, opts.ExcludeBlueprintSchema)

	// Validate data
	if err := loader.ValidateData(data); err != nil {
		return nil, fmt.Errorf("validation failed: %w", err)
	}

	// Diff validation (always enabled)
	comparer := NewDiffComparer(m.client)
	diffResult, err := comparer.Compare(ctx, data, opts)
	if err != nil {
		return nil, fmt.Errorf("diff comparison failed: %w", err)
	}

	// Use diff result to filter data
	data = diffResult.FilterData(data)

	sidebarPipeline := PlanSidebarPipeline(data.Folders, data.Pages)

	// Dry run - show what would happen
	if opts.DryRun {
		result := m.generateDryRunResult(data, diffResult, opts)
		result.SidebarPipeline = DescribeSidebarPipeline(sidebarPipeline)
		return result, nil
	}

	// Import data using new reliable importer
	importer := NewImporter(m.client)
	if len(sidebarPipeline) > 0 && opts.LogCallback != nil && opts.ShowPagesPipeline {
		opts.LogCallback("Proposed sidebar pipeline:")
		for _, line := range DescribeSidebarPipeline(sidebarPipeline) {
			opts.LogCallback(fmt.Sprintf("  %s", line))
		}
	}
	result, err := importer.Import(ctx, data, opts)
	if err != nil {
		return nil, fmt.Errorf("import failed: %w", err)
	}

	// Import permissions (blueprint and action permissions depend on resources existing)
	importer.importPermissions(ctx, diffResult)

	// Merge any permission errors into result
	result.Errors = importer.errors.ToStringSlice()

	result.Success = true
	result.Message = "Successfully imported data"

package migrate

import (
	"context"
	"fmt"
	"strings"
	"sync"

	"github.com/port-experimental/port-cli/internal/api"
	"github.com/port-experimental/port-cli/internal/config"
	"github.com/port-experimental/port-cli/internal/modules/export"
	"github.com/port-experimental/port-cli/internal/modules/import_module"
	"golang.org/x/sync/errgroup"
)

// Module handles migration between Port organizations.
type Module struct {
	sourceClient *api.Client
	targetClient *api.Client
}

// NewModule creates a new migration module.
func NewModule(sourceConfig, targetConfig *config.OrganizationConfig) *Module {
	return &Module{
		sourceClient: api.NewClient(sourceConfig.ClientID, sourceConfig.ClientSecret, sourceConfig.APIURL, 0),
		targetClient: api.NewClient(targetConfig.ClientID, targetConfig.ClientSecret, targetConfig.APIURL, 0),
	}
}

// Options represents migration options.
type Options struct {
	Blueprints             []string
	DryRun                 bool
	SkipEntities           bool
	IncludeResources       []string
	ExcludeBlueprints      []string // deep: exclude blueprint schema + all its resources
	ExcludeBlueprintSchema []string // shallow: exclude only the blueprint schema, keep resources
}

// Result represents the result of a migration operation.
type Result struct {
	Success             bool
	Message             string
	BlueprintsCreated   int
	BlueprintsUpdated   int
	BlueprintsSkipped   int
	EntitiesCreated     int
	EntitiesUpdated     int
	EntitiesSkipped     int
	ScorecardsCreated   int
	ScorecardsUpdated   int
	ScorecardsSkipped   int
	ActionsCreated      int
	ActionsUpdated      int
	ActionsSkipped      int
	TeamsCreated        int
	TeamsUpdated        int
	TeamsSkipped        int
	UsersCreated        int
	UsersUpdated        int
	UsersSkipped        int
	PagesCreated        int
	PagesUpdated        int
	PagesSkipped        int
	IntegrationsUpdated int
	IntegrationsSkipped int
	Errors              []string
	DiffResult          *import_module.DiffResult
}

// Execute performs the migration operation.
func (m *Module) Execute(ctx context.Context, opts Options) (*Result, error) {
	// Export from source
	sourceData, err := m.exportFromSource(ctx, opts)
	if err != nil {
		return nil, fmt.Errorf("failed to export from source: %w", err)
	}

	// Diff validation - compare source data with target organization's current state
	comparer := import_module.NewDiffComparer(m.targetClient)
	diffOpts := import_module.Options{
		SkipEntities:           opts.SkipEntities,
		IncludeResources:       opts.IncludeResources,
		ExcludeBlueprints:      opts.ExcludeBlueprints,
		ExcludeBlueprintSchema: opts.ExcludeBlueprintSchema,
	}
	diffResult, err := comparer.Compare(ctx, sourceData, diffOpts)
	if err != nil {
		return nil, fmt.Errorf("diff comparison failed: %w", err)
	}

	// Use diff result to filter data - only migrate what needs to be created or updated
	filteredData := diffResult.FilterData(sourceData)

	// Dry run - show what would happen
	if opts.DryRun {
		return m.generateDryRunResult(diffResult), nil
	}

	// Import to target using filtered data
	result, err := m.importToTarget(ctx, filteredData, diffResult)
	if err != nil {
		return nil, fmt.Errorf("failed to import to target: %w", err)
	}

	result.Success = true
	result.Message = "Migration completed successfully"
	result.DiffResult = diffResult
	return result, nil
}

